package evaluation

import (
	"testing"

	"github.com/stretchr/testify/assert"
)

func TestMetrics_RecordEvaluation(t *testing.T) {
	m := &Metrics{}

	m.RecordEvaluation()
	m.RecordEvaluation()

	assert.Equal(t, int64(2), m.Total())
}

func TestMetrics_RecordMatch(t *testing.T) {
	m := &Metrics{}

	m.RecordEvaluation()
	m.RecordMatch()
	m.RecordEvaluation()

	assert.Equal(t, int64(2), m.Total())
	assert.Equal(t, int64(1), m.Matches())
}

func TestMetrics_RecordError(t *testing.T) {
	m := &Metrics{}

	m.RecordEvaluation()
	m.RecordError()
	m.RecordEvaluation()
	m.RecordMatch()

	assert.Equal(t, int64(2), m.Total())
	assert.Equal(t, int64(1), m.Matches())
	assert.Equal(t, int64(1), m.Errors())
}

func TestMetrics_Snapshot(t *testing.T) {
	m := &Metrics{}

	m.RecordEvaluation()
	m.RecordMatch()
	m.RecordEvaluation()
	m.RecordError()

	snapshot := m.Snapshot()

	assert.Equal(t, int64(2), snapshot.Total)
	assert.Equal(t, int64(1), snapshot.Matches)
	assert.Equal(t, int64(1), snapshot.Errors)
}

func TestMetrics_ThreadSafe(t *testing.T) {
	m := &Metrics{}

	// Run concurrent operations
	done := make(chan bool)

	for i := 0; i < 10; i++ {
		go func() {
			for j := 0; j < 100; j++ {
				m.RecordEvaluation()
				if j%2 == 0 {
					m.RecordMatch()
				} else {
					m.RecordError()
				}
			}
			done <- true
		}()
	}

	for i := 0; i < 10; i++ {
		<-done
	}

	assert.Equal(t, int64(1000), m.Total())
	assert.Equal(t, int64(500), m.Matches())
	assert.Equal(t, int64(500), m.Errors())
}

